SELECT COUNT(*) AS TotalDataExports
FROM data_exports de
WHERE de.request_id = (
    SELECT MAX(dr.request_id)
    FROM data_requests dr
    WHERE dr.user_id = (
        SELECT MAX(user_id)
        FROM users
    )
);

SELECT sensor_id, AVG(data_quality_score) AS avg_score, MIN(data_quality_score) AS min_score, MAX(data_quality_score) AS max_score
FROM irradiance_data
GROUP BY sensor_id;

SELECT COUNT(*)
FROM irradiance_data
WHERE irradiance_id BETWEEN 1 AND 10;

SELECT SUM(data_quality_score) AS total_quality_score
FROM (
    SELECT data_quality_score FROM weather_data WHERE location_id = 0
    UNION ALL
    SELECT data_quality_score FROM irradiance_data WHERE location_id = 0
) AS combined_data;
